diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 0200525a718d..cbb9129bc33b 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7279,9 +7279,9 @@ InstructionCost LoopVectorizationPlanner::cost(VPlan &Plan,
 /// in \p CostCtx. This means the VPlan contains simplification that the legacy
 /// cost-model did not account for.
 static bool planContainsAdditionalSimplifications(VPlan &Plan,
-                                                  VPCostContext &CostCtx,
-                                                  Loop *TheLoop) {
-  // First collect all instructions for the recipes in Plan.
+                                                    VPCostContext &CostCtx,
+                                                    Loop *TheLoop) {
+  // Collect all original IR instructions referenced by recipes in the VPlan.
   auto GetInstructionForCost = [](const VPRecipeBase *R) -> Instruction * {
     if (auto *S = dyn_cast<VPSingleDefRecipe>(R))
       return dyn_cast_or_null<Instruction>(S->getUnderlyingValue());
@@ -7289,35 +7289,45 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
       return &WidenMem->getIngredient();
     return nullptr;
   };
-
   DenseSet<Instruction *> SeenInstrs;
   auto Iter = vp_depth_first_deep(Plan.getEntry());
   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(Iter)) {
     for (VPRecipeBase &R : *VPBB) {
       if (auto *IR = dyn_cast<VPInterleaveRecipe>(&R)) {
         auto *IG = IR->getInterleaveGroup();
-        unsigned NumMembers = IG->getNumMembers();
-        for (unsigned I = 0; I != NumMembers; ++I) {
+        for (unsigned I = 0, N = IG->getNumMembers(); I != N; ++I)
           if (Instruction *M = IG->getMember(I))
             SeenInstrs.insert(M);
-        }
         continue;
       }
       if (Instruction *UI = GetInstructionForCost(&R))
         SeenInstrs.insert(UI);
     }
   }
-
-  // Return true if the loop contains any instructions that are not also part of
-  // the VPlan or are skipped for VPlan-based cost computations. This indicates
-  // that the VPlan contains extra simplifications.
-  return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx](BasicBlock *BB) {
+  // Original behavior: detect instructions present in the loop but not represented
+  // in the VPlan and not skipped (extra simplifications).
+  bool HasExtra = any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx](BasicBlock *BB) {
     return any_of(*BB, [&SeenInstrs, &CostCtx](Instruction &I) {
       if (isa<PHINode>(&I))
         return false;
       return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
     });
   });
+  // Additional heuristic: detect trivially constant-foldable instructions (all
+  // operands constants) absent from the VPlan.
+  bool HasConstFoldable = any_of(TheLoop->blocks(), [&SeenInstrs](BasicBlock *BB) {
+    return any_of(*BB, [&SeenInstrs](Instruction &I) {
+      if (isa<PHINode>(&I) || I.isTerminator() || isa<LoadInst>(&I) || isa<StoreInst>(&I))
+        return false;
+      if (!I.getNumOperands())
+        return false;
+      for (Use &Op : I.operands())
+        if (!isa<Constant>(Op.get()))
+          return false;
+      return true;
+    });
+  });
+  return HasExtra || HasConstFoldable;
 }
 #endif

